const item = $input.first().json;
const iso = new Date().toISOString();
const stamp = iso.replace(/[:.]/g, '-');
const date = iso.slice(0, 10);
let raw = item.message ? (item.message.content || '') : '';
// Strip </think> blocks (native Ollama thinking model)
let content = raw.includes('</think>') ? raw.split('</think>').pop().trim() : raw.trim();
// Fallback: if result doesn't start with a markdown heading, find first '# '
if (content && !content.startsWith('#')) {
  const hIdx = content.search(/(?:^|\n)# /);
  if (hIdx !== -1) content = content.slice(content[hIdx] === '\n' ? hIdx + 1 : hIdx).trim();
}
if (!content) content = '# Local Loop Report\n\n## Verdict\nFAIL: Ollama returned no completion.\n\n```json\n' + JSON.stringify(item).slice(0, 2000) + '\n```';
const report = '<!-- local-loop-5min -->\n<!-- generated_at: ' + iso + ' -->\n\n' + content.trim() + '\n';
const report_path = 'reports/local-worker/' + date + '/' + stamp + '.md';
return [{ json: { report, report_base64: Buffer.from(report, 'utf8').toString('base64'), report_path, content, iso } }];

var full = $input.first().json.message ? ($input.first().json.message.content || '') : '';
var raw = full.includes('</think>') ? full.split('</think>').pop().trim() : full.trim();
// Try code fence first
var allFences = [];
var fenceRe = /```(?:sh|bash|shell)?\n?([\s\S]*?)```/g;
var fm;
while ((fm = fenceRe.exec(raw)) !== null) allFences.push(fm[1].trim());
var script = allFences.length ? allFences[allFences.length - 1] : '';
// Fallback: look for shebang line
if (!script) {
  var sIdx = raw.indexOf('#!/');
  if (sIdx !== -1) script = raw.slice(sIdx).trim();
}
if (!script || /^#\s*no.?op\s*$/im.test(script)) {
  return [{ json: { script: '', script_b64: '', safe: true, noop: true, reason: 'no-op', raw: raw.slice(0,500) } }];
}
// Must start with shebang
if (!script.startsWith('#!/')) {
  return [{ json: { script: '', script_b64: '', safe: true, noop: true, reason: 'no shebang', raw: raw.slice(0,500) } }];
}
var blocked = ['rm -rf','rm -r',' rm ','git push','git reset','git commit','apt-get','pip install','> /etc/','> /usr/','> /bin/',':(){','mkfs'];
var hit = blocked.find(function(b){ return script.indexOf(b) !== -1; }) || '';
if (hit) return [{ json: { script: '', script_b64: '', safe: false, noop: true, reason: 'blocked: ' + hit, raw: raw.slice(0,500) } }];
if (script.indexOf('/home/') !== -1 && script.indexOf('/home/cbk/qwen-agent-collective') === -1) {
  return [{ json: { script: '', script_b64: '', safe: false, noop: true, reason: 'path outside repo', raw: raw.slice(0,500) } }];
}
return [{ json: { script, script_b64: Buffer.from(script,'utf8').toString('base64'), safe: true, noop: false, reason: 'ok', raw: raw.slice(0,500) } }];

var full = $input.first().json.message ? ($input.first().json.message.content || '') : '';
var raw = full.includes('</think>') ? full.split('</think>').pop().trim() : full.trim();
if (!raw) raw = 'chore: automated improvement by local-loop';
var lines = raw.trim().split('\n').map(function(l){ return l.trim(); }).filter(function(l){ return l; });
var thinkLeaks = ['okay,', "let's", 'i need', 'the user', "here's", 'first,', 'so,', 'alright', 'sure,', 'well,'];
var first = lines.find(function(l){ return !thinkLeaks.some(function(t){ return l.toLowerCase().startsWith(t); }); }) || lines[0] || 'chore: automated improvement by local-loop';
first = first.replace(/^[\'"]+|[\'"]+$/g, '').slice(0, 72);
if (!first || first.length < 5) first = 'chore: automated improvement by local-loop';
var msg = first + '\n\nCo-authored-by: local-loop-agent <n8n@local>';
return [{ json: { msg_b64: Buffer.from(msg,'utf8').toString('base64'), commit_message: first } }];
